"use strict";parserFactory.register("readnovelfull.org",()=>new ReadnovelfullorgParser);class ReadnovelfullorgParser extends Parser{constructor(){super()}async getChapterUrls(e){let r=new URL(e.baseURI),t=`https://${r.hostname}/api/novels${r.pathname}/chapters?source=detail`;return[...(await HttpClient.wrapFetch(t)).responseXML.querySelectorAll("ul.chapter-list a")].map(this.linkToChapter).reverse()}linkToChapter(e){return{sourceUrl:e.href,title:e.querySelector(".chapter-title").textContent}}findContent(e){return e.querySelector(".content-inner")}extractTitleImpl(e){return e.querySelector("h1")}findChapterTitle(e){return[...e.querySelectorAll(".breadcrumbs-item")].pop()}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.img-cover")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.section-body p")]}}